174	func postGraphQLBeadLookupErr(h http.Handler, query string) (graphQLBeadResponse, error) {
175		rawBody, err := json.Marshal(map[string]string{"query": query})
176		if err != nil {
177			return graphQLBeadResponse{}, fmt.Errorf("marshal GraphQL request: %w", err)
178		}
179		req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewReader(rawBody))
180		req.Header.Set("Content-Type", "application/json")
181		req.RemoteAddr = "127.0.0.1:12345"
182		w := httptest.NewRecorder()
183		h.ServeHTTP(w, req)
184		if w.Code != http.StatusOK {
185			return graphQLBeadResponse{}, fmt.Errorf("GraphQL status: want 200, got %d: %s", w.Code, w.Body.String())
186		}
187		var resp graphQLBeadResponse
188		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
189			return graphQLBeadResponse{}, fmt.Errorf("decode GraphQL response: %w\nbody: %s", err, w.Body.String())
190		}
191		if len(resp.Errors) > 0 {
192			return graphQLBeadResponse{}, fmt.Errorf("GraphQL errors: %+v", resp.Errors)
193		}
194		return resp, nil
195	}
