205	func measureGraphQLBeadLookup(tb testing.TB, h http.Handler, beadID string, iterations int) (time.Duration, time.Duration) {
206		tb.Helper()
207		samples := make([]time.Duration, 0, iterations)
208		query := beadDetailQuery(beadID)
209		for i := 0; i < iterations; i++ {
210			start := time.Now()
211			resp := postGraphQLBeadLookup(tb, h, query)
212			elapsed := time.Since(start)
213			if resp.Data.Bead == nil || resp.Data.Bead.ID != beadID || resp.Data.Bead.Title == "" {
214				tb.Fatalf("unexpected bead response: %+v", resp.Data.Bead)
215			}
216			samples = append(samples, elapsed)
217		}
218		return percentileDurations(samples)
219	}
220	
221	func percentileDurations(samples []time.Duration) (time.Duration, time.Duration) {
222		sort.Slice(samples, func(i, j int) bool { return samples[i] < samples[j] })
223		return percentileDuration(samples, 50), percentileDuration(samples, 95)
224	}
225	
226	func percentileDuration(sorted []time.Duration, pct int) time.Duration {
227		if len(sorted) == 0 {
228			return 0
229		}
230		idx := (len(sorted)*pct + 99) / 100
231		if idx < 1 {
232			idx = 1
233		}
234		if idx > len(sorted) {
235			idx = len(sorted)
236		}
237		return sorted[idx-1]
238	}
