 80	// VerifyFiles checks whether any recorded files for the entry exist on disk.
 81	// Returns true if at least one file exists, false if all are missing.
 82	func (e *InstalledEntry) VerifyFiles() bool {
 83		if len(e.Files) == 0 {
 84			return false
 85		}
 86		for _, f := range e.Files {
 87			expanded := ExpandHome(f)
 88			if _, err := os.Stat(expanded); err == nil {
 89				return true
 90			}
 91			// Check if it's a symlink that resolves
 92			if info, err := os.Lstat(expanded); err == nil && info.Mode()&os.ModeSymlink != 0 {
 93				target, err := os.Readlink(expanded)
 94				if err == nil {
 95					if !filepath.IsAbs(target) {
 96						target = filepath.Join(filepath.Dir(expanded), target)
 97					}
 98					if _, err := os.Stat(target); err == nil {
 99						return true
100					}
101				}
102			}
103		}
104		return false
105	}
