107	// FindInstalled returns the entry for name, or nil if not installed.
108	func (s *InstalledState) FindInstalled(name string) *InstalledEntry {
109		for i := range s.Installed {
110			if s.Installed[i].Name == name {
111				return &s.Installed[i]
112			}
113		}
114		return nil
115	}
116	
117	// AddOrUpdate adds a new entry or replaces an existing one.
118	func (s *InstalledState) AddOrUpdate(entry InstalledEntry) {
119		for i := range s.Installed {
120			if s.Installed[i].Name == entry.Name {
121				s.Installed[i] = entry
122				return
123			}
124		}
125		s.Installed = append(s.Installed, entry)
126	}
127	
128	// Remove removes an entry by name. Returns false if not found.
129	func (s *InstalledState) Remove(name string) bool {
130		for i := range s.Installed {
131			if s.Installed[i].Name == name {
132				s.Installed = append(s.Installed[:i], s.Installed[i+1:]...)
133				return true
134			}
135		}
136		return false
137	}

